Func<double, double, Tekla.Structures.Model.ContourPlate> makeBP = (cx, cy) => {
    var cp = new Tekla.Structures.Model.ContourPlate();
    cp.Contour.AddContourPoint(new Tekla.Structures.Model.ContourPoint(new Tekla.Structures.Geometry3d.Point(cx-250, cy-250, 0), null));
    cp.Contour.AddContourPoint(new Tekla.Structures.Model.ContourPoint(new Tekla.Structures.Geometry3d.Point(cx+250, cy-250, 0), null));
    cp.Contour.AddContourPoint(new Tekla.Structures.Model.ContourPoint(new Tekla.Structures.Geometry3d.Point(cx+250, cy+250, 0), null));
    cp.Contour.AddContourPoint(new Tekla.Structures.Model.ContourPoint(new Tekla.Structures.Geometry3d.Point(cx-250, cy+250, 0), null));
    cp.Profile.ProfileString = "PL20";
    cp.Material.MaterialString = "S275";
    cp.Class = "3";
    cp.Name = "BASE PLATE";
    return cp;
};
var bp1 = makeBP(0, 0);
bool ok1 = bp1.Insert();
var bp2 = makeBP(5000, 0);
bool ok2 = bp2.Insert();
return new {
    bp_a1 = new { inserted = ok1, guid = bp1.Identifier.GUID.ToString() },
    bp_a2 = new { inserted = ok2, guid = bp2.Identifier.GUID.ToString() }
};
